Javascript.validate:

var inputDate = Services.getValue(JOrderDate.dataBinding);
var isInFuture = isFutureDate(inputDate);
var err = null;
if( isInFuture == true )
{	err = ErrorCode.getErrorCode("CaseMan_dateCannotBeInTheFuture_Msg");
}
return err;
